"use client";

import { useEffect, useRef, useState } from "react";
import { useWizardStore, type AspectRatio } from "@/store/wizard";
import * as fabric from "fabric";
import { RectangleHorizontal, Square, Smartphone } from "lucide-react";

const ASPECT_SIZES: Record<AspectRatio, { w: number; h: number }> = {
  "1:1": { w: 800, h: 800 },
  "3:4": { w: 800, h: 1067 },
  "4:3": { w: 800, h: 600 },
  "4:5": { w: 800, h: 1000 },
  "5:4": { w: 800, h: 640 },
  "9:16": { w: 720, h: 1280 },
  "16:9": { w: 1280, h: 720 },
};

const TEXT_TEMPLATES = [
  { label: "Menu of the Day", text: "MENU OF THE DAY", fontSize: 42, color: "#ffffff" },
  { label: "Weekend Special", text: "WEEKEND SPECIAL", fontSize: 38, color: "#f59e0b" },
  { label: "Chef's Pick", text: "CHEF'S PICK", fontSize: 44, color: "#ef4444" },
  { label: "Limited Time", text: "LIMITED TIME OFFER", fontSize: 36, color: "#10b981" },
];

export default function StepCanvas() {
  const store = useWizardStore();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fabricRef = useRef<fabric.Canvas | null>(null);
  const [activeTemplate, setActiveTemplate] = useState<number | null>(null);

  const aspectRatio = store.selectedAspectRatio;
  const size = ASPECT_SIZES[aspectRatio];

  useEffect(() => {
    if (!canvasRef.current || !store.generatedImageUrl) return;

    const canvas = new fabric.Canvas(canvasRef.current, {
      width: size.w,
      height: size.h,
      backgroundColor: "#111",
    });
    fabricRef.current = canvas;

    fabric.FabricImage.fromURL(store.generatedImageUrl, { crossOrigin: "anonymous" }).then(
      (img) => {
        const scale = Math.max(size.w / (img.width || 1), size.h / (img.height || 1));
        img.set({
          scaleX: scale,
          scaleY: scale,
          originX: "center",
          originY: "center",
          left: size.w / 2,
          top: size.h / 2,
          selectable: false,
          evented: false,
        });
        canvas.add(img);
        canvas.sendObjectToBack(img);
        canvas.renderAll();
      }
    );

    return () => {
      canvas.dispose();
    };
  }, [store.generatedImageUrl, aspectRatio, size.w, size.h]);

  const addTextTemplate = (idx: number) => {
    const canvas = fabricRef.current;
    if (!canvas) return;

    if (activeTemplate !== null) {
      const objects = canvas.getObjects().filter((o) => o instanceof fabric.Textbox);
      objects.forEach((o) => canvas.remove(o));
    }

    const tpl = TEXT_TEMPLATES[idx];
    const text = new fabric.Textbox(tpl.text, {
      left: size.w / 2,
      top: size.h * 0.85,
      originX: "center",
      originY: "center",
      fontSize: tpl.fontSize,
      fill: tpl.color,
      fontFamily: "Arial",
      fontWeight: "bold",
      textAlign: "center",
      width: size.w * 0.8,
      shadow: new fabric.Shadow({ color: "rgba(0,0,0,0.7)", blur: 8, offsetX: 2, offsetY: 2 }),
    });
    canvas.add(text);
    canvas.setActiveObject(text);
    canvas.renderAll();
    setActiveTemplate(idx);
  };

  const changeAspect = (ratio: AspectRatio) => {
    store.setAspectRatio(ratio);
  };

  const exportCanvas = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    const dataUrl = canvas.toDataURL({ format: "png", quality: 1, multiplier: 2 });
    const a = document.createElement("a");
    a.href = dataUrl;
    a.download = `foodsocial_${Date.now()}.png`;
    a.click();
  };

  return (
    <div className="flex flex-col lg:flex-row gap-6">
      <div className="flex-1 flex justify-center">
        <div
          className="border border-gray-700 rounded-xl overflow-hidden"
          style={{ maxWidth: size.w / 2, maxHeight: size.h / 2 }}
        >
          <canvas
            ref={canvasRef}
            style={{ width: size.w / 2, height: size.h / 2 }}
          />
        </div>
      </div>

      <div className="w-full lg:w-72 flex flex-col gap-6">
        <div>
          <h3 className="text-sm font-semibold text-gray-400 mb-2 uppercase tracking-wider">
            Aspect Ratio
          </h3>
          <div className="flex flex-wrap gap-2">
            {(Object.keys(ASPECT_SIZES) as AspectRatio[]).map((ratio) => (
              <button
                key={ratio}
                onClick={() => changeAspect(ratio)}
                aria-label={`Set aspect ratio to ${ratio}`}
                className={`px-3 py-2 rounded-lg text-sm cursor-pointer transition-colors duration-200 ${
                  aspectRatio === ratio
                    ? "bg-amber-600 text-white"
                    : "bg-gray-800 text-gray-400 hover:bg-gray-700"
                }`}
              >
                {ratio}
              </button>
            ))}
          </div>
        </div>

        <div>
          <h3 className="text-sm font-semibold text-gray-400 mb-2 uppercase tracking-wider">
            Text Overlay
          </h3>
          <div className="flex flex-col gap-2">
            {TEXT_TEMPLATES.map((tpl, i) => (
              <button
                key={tpl.label}
                onClick={() => addTextTemplate(i)}
                aria-label={`Add ${tpl.label} text overlay`}
                className={`px-3 py-2 rounded-lg text-sm text-left cursor-pointer transition-colors duration-200 ${
                  activeTemplate === i
                    ? "bg-amber-600/20 ring-1 ring-amber-500 text-amber-400"
                    : "bg-gray-800 text-gray-300 hover:bg-gray-700"
                }`}
              >
                {tpl.label}
              </button>
            ))}
          </div>
        </div>

        <button
          onClick={exportCanvas}
          className="mt-auto px-4 py-3 bg-amber-600 text-white rounded-xl font-semibold cursor-pointer hover:bg-amber-500 transition-colors duration-200"
        >
          Download Image
        </button>
      </div>
    </div>
  );
}
